codeunit 50100 N
{
    procedure Skel(var Cust: Record Customer)
    var
        i: Integer;
    begin
        if Cust.IsEmpty() then
            Cust.Init()
        else
            Cust.Modify();
        case i of
            1:
                Cust.Insert();
            else
                Cust.Delete();
        end;
        while i < 10 do
            i := i + 1;
        for i := 1 to 5 do
            Cust.FindFirst();
        repeat
            Cust.Next();
        until i = 0;
    end;
}
